import asyncio
import json
from playwright.async_api import async_playwright, Page
import anthropic

client = anthropic.Anthropic()

async def discover_form_fields(page: Page) -> list:
    'Return a list of field descriptors from the current page form.'
    return await page.evaluate('''() => {
        const fields = [];
        document.querySelectorAll('input, select, textarea').forEach(el => {
            if (el.type === 'hidden' || el.type === 'submit') return;
            const label = document.querySelector(

            )?.textContent?.trim() || el.placeholder || el.name || el.id;
            fields.push({
                id: el.id || el.name,
                type: el.type || el.tagName.toLowerCase(),
                label: label,
                required: el.required,
                visible: !!(el.offsetWidth || el.offsetHeight),
                disabled: el.disabled,
                options: el.tagName === 'SELECT'
                    ? Array.from(el.options).map(o => ({value: o.value, text: o.text}))
                    : null,
            });
        });
        return fields;
    }''')

async def get_validation_errors(page: Page) -> list:
    'Return list of validation error messages visible on the page.'
    return await page.evaluate('''() => {
        const errors = [];
        document.querySelectorAll('[aria-invalid="true"]').forEach(el => {
            const errId = el.getAttribute('aria-describedby');
            const msg = errId ? document.getElementById(errId)?.textContent : 'Invalid';
            errors.push({field: el.name || el.id, message: msg?.trim()});
        });
        document.querySelectorAll('.error-message, .field-error, [role="alert"]').forEach(el => {
            errors.push({field: null, message: el.textContent?.trim()});
        });
        return errors;
    }''')

async def fill_form_with_ai(page: Page, data: dict, max_retries: int = 3):
    for attempt in range(max_retries):
        fields = await discover_form_fields(page)

        # Ask LLM to map fields to data values
        response = client.messages.create(
            model='claude-opus-4-5',
            max_tokens=1024,
            messages=[{
                'role': 'user',
                'content': (
                    f'Form fields: {json.dumps(fields, indent=2)}

'
                    f'Data to fill: {json.dumps(data, indent=2)}

'
                    'Return a JSON array of fill instructions like: '
                    '[{"id": "field-id", "value": "value", "type": "fill|select|check"}]'
                ),
            }],
        )

        instructions = json.loads(response.content[0].text)

        # Execute fill instructions
        for instr in instructions:
            field_id = instr['id']
            value = instr['value']
            action = instr.get('type', 'fill')
            locator = page.locator(f'[id="{field_id}"], [name="{field_id}"]').first
            if action == 'fill':
                await locator.fill(str(value))
            elif action == 'select':
                await locator.select_option(str(value))
            elif action == 'check' and value:
                await locator.check()

        # Submit
        await page.get_by_role('button', name=lambda n: 'submit' in n.lower() or 'save' in n.lower()).click()
        await page.wait_for_load_state('networkidle')

        errors = await get_validation_errors(page)
        if not errors:
            print('Form submitted successfully')
            return True

        print(f'Attempt {attempt+1}: validation errors: {errors}')
        # Adjust data based on errors -- next loop iteration will retry
        data['_errors'] = errors  # agent can read these on next pass

    return False

async def main():
    async with async_playwright() as p:
        browser = await p.chromium.launch(headless=True)
        page = await browser.new_page()
        await page.goto('https://example.com/contact')
        await fill_form_with_ai(page, {
            'name': 'Alice Smith',
            'email': 'alice@example.com',
            'message': 'Interested in your services.',
        })
        await browser.close()

asyncio.run(main())

import asyncio
from playwright.async_api import async_playwright, Page

async def fill_date_picker(page: Page, label: str, date_str: str):
    'Fill a custom date picker by setting the underlying input value via JS.'
    # Most date pickers bind to a hidden or visible input[type=date]
    date_input = page.get_by_label(label)
    input_type = await date_input.get_attribute('type')
    if input_type == 'date':
        # Native date input: use fill() with ISO format YYYY-MM-DD
        await date_input.fill(date_str)
    else:
        # Custom date picker: set value via JS and trigger change event
        await page.evaluate(
            '''([selector, value]) => {
                const el = document.querySelector(selector);
                if (el) {
                    el.value = value;
                    el.dispatchEvent(new Event('input', {bubbles: true}));
                    el.dispatchEvent(new Event('change', {bubbles: true}));
                }
            }''',
            [f'[aria-label="{label}"]', date_str]
        )

async def fill_rich_text_editor(page: Page, label: str, text: str):
    'Fill a TinyMCE or Quill rich text editor with plain text.'
    # TinyMCE renders in an iframe; target the iframe body
    editor_frame = page.frame_locator(f'[id*="mce"] iframe, .ql-editor').first
    if editor_frame:
        body = editor_frame.locator('body')
        await body.click()
        await body.fill(text)
        return
    # Quill editor: the contenteditable div
    quill_editor = page.locator('.ql-editor')
    if await quill_editor.is_visible():
        await quill_editor.click()
        await page.keyboard.press('Control+A')
        await page.keyboard.type(text)

async def fill_file_upload(page: Page, label: str, file_path: str):
    'Set files on a file input element.'
    file_input = page.get_by_label(label)
    await file_input.set_input_files(file_path)
    # Verify the file appears in the UI
    await page.wait_for_function(
        '''() => {
            const inputs = document.querySelectorAll('input[type="file"]');
            return Array.from(inputs).some(el => el.files && el.files.length > 0);
        }'''
    )

import asyncio
from playwright.async_api import async_playwright, Page
from typing import List, Dict, Any

async def detect_wizard_step(page: Page) -> dict:
    'Return current step number and total steps from progress indicator.'
    result = await page.evaluate('''() => {
        const steps = document.querySelectorAll('.wizard-step, [role="tab"]');
        const current = document.querySelector('.wizard-step.active, [aria-selected="true"]');
        const currentIdx = Array.from(steps).indexOf(current);
        return {total: steps.length, current: currentIdx + 1};
    }''')
    return result or {'total': 1, 'current': 1}

async def fill_wizard_form(
    page: Page,
    steps: List[Dict[str, Any]],
) -> bool:
    'Fill a multi-step wizard form, advancing through each step.'
    for step_data in steps:
        wizard_state = await detect_wizard_step(page)
        print(f'Step {wizard_state["current"]} of {wizard_state["total"]}')

        # Fill fields for this step
        for field_label, value in step_data['fields'].items():
            field = page.get_by_label(field_label)
            field_type = await field.get_attribute('type') or 'text'

            if field_type in ('text', 'email', 'password', 'tel', 'number'):
                await field.fill(str(value))
            elif field_type == 'date':
                await field.fill(value)  # expects YYYY-MM-DD
            elif field_type == 'checkbox':
                if value:
                    await field.check()
                else:
                    await field.uncheck()

        # Click next or submit button
        next_button = page.get_by_role('button', name=step_data.get('next_button', 'Next'))
        await next_button.click()
        await page.wait_for_load_state('networkidle')

        # Check for validation errors before proceeding
        error_count = await page.locator('[aria-invalid="true"]').count()
        if error_count > 0:
            print(f'Validation errors on step {wizard_state["current"]}')
            return False

    return True

async def main():
    async with async_playwright() as p:
        browser = await p.chromium.launch(headless=True)
        page = await browser.new_page()
        await page.goto('https://example.com/checkout')

        success = await fill_wizard_form(page, [
            {'fields': {'First name': 'Alice', 'Last name': 'Smith'}, 'next_button': 'Continue'},
            {'fields': {'Street address': '123 Main St', 'City': 'Springfield', 'ZIP': '12345'}, 'next_button': 'Continue'},
            {'fields': {'Card number': '4111111111111111', 'Expiry': '12/26', 'CVV': '123'}, 'next_button': 'Place order'},
        ])
        print('Order placed:', success)
        await browser.close()

asyncio.run(main())
